import type { listenerMiddlewareInstance, RootState } from '@/store/index'
import { isAuthenticated } from '@/store/authSlice'
import { removeUndeployedSafe } from './undeployedSafesSlice'
import { cgwApi as counterfactualSafesApi } from '@safe-global/store/gateway/AUTO_GENERATED/counterfactual-safes'

export const counterfactualSyncListener = (listenerMiddleware: typeof listenerMiddlewareInstance) => {
  // Sync removeUndeployedSafe to backend
  listenerMiddleware.startListening({
    actionCreator: removeUndeployedSafe,
    effect: async (action, listenerApi) => {
      const state = listenerApi.getState() as RootState
      if (!isAuthenticated(state)) return

      const { chainId, address } = action.payload

      // Look up the entry in the *pre-action* state — by the time this effect
      // runs, the reducer has already removed it from current state. Backend
      // DELETE rejects non-creators with 40x, so skip the call for safes the
      // current user didn't create (e.g. ones synced from a space endpoint).
      // Read the raw slice directly (no memoized selector) to keep the check
      // dependency-free and easy to test.
      const originalState = listenerApi.getOriginalState() as RootState
      const removed = originalState.undeployedSafes?.[chainId]?.[address]
      // Treat undefined as `true` for backwards compatibility with entries
      // persisted before the isCreator flag existed.
      const wasCreator = removed?.isCreator !== false
      if (!wasCreator) return

      try {
        await listenerApi
          .dispatch(
            counterfactualSafesApi.endpoints.counterfactualSafesDeleteV1.initiate({
              deleteCounterfactualSafesDto: { safes: [{ chainId, address }] },
            }),
          )
          .unwrap()
      } catch (e) {
        console.error('[CF Sync] Failed to delete CF safe from backend', e)
      }
    },
  })
}

import { type RootState } from '@/store'
import { createSelector, createSlice, type PayloadAction } from '@reduxjs/toolkit'
import { selectChainIdAndSafeAddress } from '@/store/common'
import type {
  UndeployedSafe,
  UndeployedSafesState,
  UndeployedSafeStatus,
  PredictedSafeProps,
  ReplayedSafeProps,
  PayMethod,
} from '../types'
import { PendingSafeStatus } from '../types'

const initialState: UndeployedSafesState = {}

export const undeployedSafesSlice = createSlice({
  name: 'undeployedSafes',
  initialState,
  reducers: {
    addUndeployedSafe: (
      state,
      action: PayloadAction<{
        chainId: string
        address: string
        type: PayMethod
        safeProps: PredictedSafeProps | ReplayedSafeProps
        // Default true — locally-initiated creations are always by the current user.
        // Sync from the space endpoint (safes created by other members) passes false.
        isCreator?: boolean
      }>,
    ) => {
      const { chainId, address, type, safeProps, isCreator = true } = action.payload

      if (!state[chainId]) {
        state[chainId] = {}
      }

      state[chainId][address] = {
        props: safeProps,
        status: {
          status: PendingSafeStatus.AWAITING_EXECUTION,
          type,
        },
        isCreator,
      }
    },

    addUndeployedSafes: (_, { payload }: PayloadAction<UndeployedSafesState>) => {
      // We must return as we are overwriting the entire state
      return payload
    },

    updateUndeployedSafeStatus: (
      state,
      action: PayloadAction<{ chainId: string; address: string; status: Omit<UndeployedSafeStatus, 'type'> }>,
    ) => {
      const { chainId, address, status } = action.payload

      if (!state[chainId]?.[address]) return state

      const existing = state[chainId][address]
      state[chainId][address] = {
        ...existing,
        props: existing.props,
        status: {
          ...existing.status,
          ...status,
        },
      }
    },

    removeUndeployedSafe: (state, action: PayloadAction<{ chainId: string; address: string }>) => {
      const { chainId, address } = action.payload
      if (!state[chainId]) return state

      delete state[chainId][address]

      if (Object.keys(state[chainId]).length > 0) return state

      delete state[chainId]
    },
  },
})

